package com.hospital.management.controller.billing;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.BillServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;import java.util.*;@WebServlet("/billing/edit")public class BillEditServlet extends HttpServlet{private final BillService service;public BillEditServlet(){this(new BillServiceImpl());}public BillEditServlet(BillService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=BillingRequest.id(q.getParameter("id"));Bill b=id==null?null:service.getBill(id,BillingRequest.user(q)).orElse(null);if(b==null){r.sendError(404);return;}if(!"UNPAID".equals(b.getStatus())){r.sendError(409);return;}show(q,r,form(b),b);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{BillForm f=BillingRequest.bill(q);ServiceResult<Void>x=service.updateBill(f,BillingRequest.audit(q),BillingRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/billing/view?id="+f.getBillId()+"&message=updated");return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,f,f.getBillId()==null?null:service.getBill(f.getBillId(),BillingRequest.user(q)).orElse(null));}private void show(HttpServletRequest q,HttpServletResponse r,BillForm f,Bill b)throws ServletException,IOException{if(b==null){r.sendError(404);return;}q.setAttribute("bill",b);q.setAttribute("billForm",f);q.setAttribute("formMode","EDIT");q.getRequestDispatcher("/WEB-INF/views/billing/form.jsp").forward(q,r);}private BillForm form(Bill b){BillForm f=new BillForm();f.setBillId(b.getBillId());f.setPatientId(b.getPatientId());f.setAppointmentId(b.getAppointmentId());f.setTaxAmount(b.getTaxAmount().toString());f.setDiscountAmount(b.getDiscountAmount().toString());List<BillItemForm>x=new ArrayList<>();for(BillItem i:b.getItems()){BillItemForm z=new BillItemForm();z.setItemType(i.getItemType());z.setDescription(i.getDescription());z.setQuantity(i.getQuantity().toString());z.setUnitPrice(i.getUnitPrice().toString());x.add(z);}f.setItems(x);return f;}}
